本篇概述什么是数据结构、数据结构与算法的关系以及相关概念术语。 

一、笔记&ensp;&ensp; &ensp; 数据结构&ensp;&ensp; &ensp; 数据 指能输入到计算机中并被处理的符号的总称。&ensp;&ensp; &ensp; 数据元素 是数据的基本单位，性质相同的同一类数据元素称为 数据对象。&ensp;&ensp; &ensp; 数据类型 指数据对象集合和数据集合相关联的操作集。&ensp;&ensp; &ensp; 数据结构 通常包含数据逻辑结构、物理结构以及数据相关联的操作。逻辑结构：线性结构、树结构、图；物理存储：顺序、链接、散列、索引结构。
&ensp;&ensp; &ensp; 算法分析&ensp;&ensp; &ensp; 算法 通常包含有穷性、确定性、可行性三个性质，以一组有限的指令集完成某个目标并产生输出。本书涉及的部分算法：穷举法、贪心法、分治法、回溯法。&ensp;&ensp; &ensp; 空间复杂度 $S(n)$: 算法程序在执行时占用存储单元的长度。&ensp;&ensp; &ensp; 时间复杂度 $S(n)$: 算法程序在执行时耗费时间的长度。&ensp;&ensp; &ensp; 算法分析时通常参考最坏情况复杂度、平均复杂度，平均复杂度难以度量，通常评估算法的好坏参考最坏情况复杂度。&ensp;&ensp; &ensp; 复杂度渐进表示法&ensp;&ensp; &ensp; $T(N) = O(f(N))$ 表示存在常数 $C &gt; 0, n_0 &gt; 0$ 使得当 $n \ge n_0$ 时有 $T(N) \leq Cf(N)$&ensp;&ensp; &ensp; $T(N) = \Omega (g(N))$ 表示存在常数 $C &gt; 0, n_0 &gt; 0$ 使得当 $n \ge n_0$ 时有 $T(N) \ge Cf(N)$&ensp;&ensp; &ensp; $T(N) = \Theta (h(N))$ 表示同时有 $T(N)==O(h(N))、T(N) = \Theta(h(N))$ 
&ensp;&ensp; &ensp; 算法分析 若 $T_1(N) = O(f(N))、T_2(N) = O(g(N))$，则有：&ensp;&ensp; &ensp; $T_1(N) + T_2(N) = max(O(f(N)), O(g(N)))$&ensp;&ensp; &ensp; $T_1(N) \cdot T_2(N) = O(f(N) \cdot g(N))$&ensp;&ensp; &ensp; 若 $T(N)$是关于 n 的 k 阶多项式，则 $T(N)=\Theta(n^k)$，表示复杂度只受高阶影响。
二、习题&ensp;&ensp; &ensp; 1. 最大子列和问题&ensp;&ensp; &ensp; 给定 N 个整数的序列 {$A_1, A_2, … ,A_N$}，求函数 $ \sum\limits_{k=i}^j A_k $ 最大值。

方法一：穷举法int MaxSubSeqSum1(int List[], int N) &#123;
    int ThisSum, MaxSum;
    for (int i = 0; i &lt; N; i++) &#123;        // i 为子列左端
        ThisSum = 0;
        for (int j = i; j &lt; N; j++) &#123;    // j 为子列右端
            ThisSum += List[j];
            if (ThisSum > MaxSum)
                MaxSum = ThisSum;
        &#125;
    &#125;
    return MaxSum;
&#125;
方法二：分治法int Max3(int A, int B, int C) &#123;
  return (A > B) ? (A > C ? A : C) : (B > C ? B : C);
&#125;

int DivideAndConquer(int List[], int left, int right) &#123;
  int MaxLeftSum, MaxRightSum;              // 左右子问题解
  int MaxLeftBorderSum, MaxRightBorderSum;  // 跨跃分界线解

  int LeftBorderSum, RightBorderSum;
  int center, i;

  // 递归终止
  if (left == right) &#123;
    if (List[Left] > 0)&#123;
      return List[Left];
    &#125; else &#123;
      return 0;
    &#125;
  &#125;

  // 分治
  center = (left + right) / 2;
  MaxLeftSum = DivideAndConquer(List, Left, center);
  MaxRightSum = DivideAndConquer(List, center + 1, right)

  // 求跨界的最大子列和
  MaxLeftBorderSum = 0; LeftBorderSum = 0;
  for (int i = center; i >= left; --i) &#123;
    LeftBorderSum += List[i];
    if (LeftBorderSum > MaxLeftBorderSum)&#123;
      MaxLeftBorderSum = LeftBorderSum;
    &#125;
  &#125;  // 左边扫描结束

  MaxRightBorderSum = 0; RightBorderSum = 0;
  for (int i = center + 1; i &lt;= right; ++i) &#123;
    RightBorderSum += List[i];
    if (RightBorderSum > MaxRightBorderSum) &#123;
      MaxRightBorderSum = RightBorderSum;
    &#125;
  &#125;  // 右边扫描结束

  return Max3(MaxLeftSum, MaxRightSum, MaxLeftBorderSum + MaxRightBorderSum);
&#125;

int MaxSubSeqSum2(int List[], int N) &#123;
  return DivideAndConquer(List, 0, N - 1);
&#125;
方法三：在线处理int MaxSubSeqSum3(int List[], int N) &#123;
  int ThisSum = MaxSum = 0;
  for (int i = 0; i &lt; N; i++) &#123;
    ThisSum += List[i];
    if (ThisSum > MaxSum) &#123;
      MaxSum = ThisSum;
    &#125; else if (ThisSum &lt; 0) &#123;
      ThisSum = 0;
    &#125;
  &#125;
  return MaxSum;
&#125;


