&ensp;&ensp; &ensp; 2. Maximum Subsequence Sum&ensp;&ensp; &ensp; 给定 K 个整数的序列 {$N_1, N_2, … ,N_K$}，求最大子序列和 {$N_i, N_i+1, …, N_j$}，子序列满足条件 $1 \leq i \leq j \leq K$，当输入序列全是负数时，输出最大序列和为 0，输出序列第一个数和最后一个数。
import java.util.Scanner;
public class Main &#123;

    public static void main(String[] args) &#123;
        Scanner scanner = new Scanner(System.in);
        int k = scanner.nextInt();

        int[] list = new int[k];
        for (int i = 0; i &lt; k; i++) &#123;
            list[i] = scanner.nextInt();
        &#125;
        MaxSubseqSum(list);
    &#125;

    public static void MaxSubseqSum(int[] list) &#123;
        int MaxSum = list[0], thisSum = 0;

        int fristIndex = 0, lastIndex = 0;
        for (int i = 0; i &lt; list.length; i++) &#123;
            thisSum += list[i];
            if (thisSum > MaxSum) &#123;
                lastIndex = i;
                MaxSum = thisSum;
            &#125; else if (thisSum &lt; 0) &#123;
                thisSum = 0;
            &#125;
        &#125;

        if (MaxSum &lt; 0) &#123;
            MaxSum = 0;
            fristIndex = 0;
            lastIndex = list.length - 1;
        &#125; else &#123;
            int temp = MaxSum;
            for (int j = lastIndex; j >= 0; j--) &#123;
                temp -= list[j];
                if (temp == 0) &#123;
                    fristIndex = j;
                &#125;
            &#125;
        &#125;

        System.out.println(MaxSum + " " + list[fristIndex] + " " + list[lastIndex]);
    &#125;
&#125;

&ensp;&ensp; &ensp; 3. 二分查找&ensp;&ensp; &ensp; 实现二分查找算法。

裁判测试程序样例，本题仅编写二分查找算法即可#include &lt;stdio.h>
#include &lt;stdlib.h>

#define MAXSIZE 10
#define NotFound 0
typedef int ElementType;

typedef int Position;
typedef struct LNode *List;
struct LNode &#123;
    ElementType Data[MAXSIZE];
    Position Last; /* 保存线性表中最后一个元素的位置 */
&#125;;

List ReadInput(); /* 裁判实现，细节不表。元素从下标1开始存储 */
Position BinarySearch( List L, ElementType X );

int main()
&#123;
    List L;
    ElementType X;
    Position P;

    L = ReadInput();
    scanf("%d", &amp;X);
    P = BinarySearch( L, X );
    printf("%d\n", P);

    return 0;
&#125;

/* 你的代码将被嵌在这里 */
Position BinarySearch(List L, ElementType X) &#123;
  int head = 1, end = L->Last;
  int m, flag = -1;
  while (head &lt;= end) &#123;
    m = (head + end)/2;
    if ( L->Data[m] == X) &#123;
      flag = m;
      break;
    &#125; else if (L->Data[m] > X) &#123;
      end = m - 1;
    &#125; else if (L->Data[m] &lt; X) &#123;
      head = m + 1;
    &#125;
  &#125;
  if (flag == -1) &#123;
    return NotFound;
  &#125; else &#123;
    return flag;
  &#125;
&#125;


&ensp;&ensp; &ensp; 分治法复杂度分析&ensp;&ensp; &ensp; 时间复杂度&ensp;&ensp; &ensp; &ensp; $T(N)=2T(N/2)+N$&ensp;&ensp; &ensp; &ensp; $T_1 = 1$&ensp;&ensp; &ensp; &ensp; $T_2 = 4 = 2 \cdot 2$&ensp;&ensp; &ensp; &ensp; $T_4 = 12 = 4 \cdot 3$&ensp;&ensp; &ensp; &ensp; 可推导至一般形式 $T(2^k)=2^k \cdot (k+1)$&ensp;&ensp; &ensp; &ensp; 若分割至 N，则 $T(N) = N \cdot (k+1)$，带入 $k=logN$&ensp;&ensp; &ensp; &ensp; $T(N)=NlogN+N=O(NlogN)$&ensp;&ensp; &ensp; 空间复杂度&ensp;&ensp; &ensp; &ensp; 递归而产生的空间复杂度 = 每次递归的空间复杂度 * 递归深度，单次递归需要的空间是一个与 N 无关的常量，计为 $O(1)$, 分成 2 个、4 个、N 个，则需要分 logN 次，则 $S(n)=O(logN)$&ensp;&ensp; &ensp; &ensp; 算法整体复杂度：n 个数据，求左边空间要 n/2， 右边要 n/2，跨越分界线需要扫描一次，则 $S(n)=2n=O(n)$&ensp;&ensp; &ensp; &ensp;&ensp;&ensp; &ensp; &ensp;
